// Shared empty set used to temporarily suppress subscription firing while a
// buffer is applied. Subscriptions are re-fired afterwards based on the diff
// of state before and after the flush.
const EMPTY_SUBS: Set<any> = new Set();

export function createDeferredBuffer(): DeferredBuffer {
    return { commands: [], spawned: new Set() };
}

/** Recompute the cached count of pending commands across the whole stack. */
function recountPending(world: World) {
    const ctx = world[$internal];
    let count = 0;
    for (const buffer of ctx.deferredStack) count += buffer.commands.length;
    ctx.deferredPending = count;
}

function topBuffer(world: World): DeferredBuffer {
    const stack = world[$internal].deferredStack;
    return stack[stack.length - 1];
}

/**
 * Build the `world.deferred` API. The returned object reads the world's buffer
 * stack lazily so it keeps working across `world.reset()`.
 */
export function createDeferred(world: World): Deferred {
    return {
        spawn(...traits: ConfigurableTrait[]): Entity {
            // Eagerly create a bare entity so callers get a usable handle and
            // `has`/`get` resolve against it. Its traits are deferred.
            const entity = createEntity(world);
            const buffer = topBuffer(world);
            buffer.spawned.add(entity);
            for (const config of traits) {
                buffer.commands.push({ type: 'add', entity, config });
            }
            recountPending(world);
            return entity;
        },

        destroy(entity: Entity) {
            const buffer = topBuffer(world);

            // Spawn + destroy within the same buffer nullify each other: drop
            // the entity's pending commands and remove the bare entity now. No
            // subscriptions ever fired for it, so nothing is observable.
            if (buffer.spawned.has(entity)) {
                buffer.commands = buffer.commands.filter((cmd) => cmd.entity !== entity);
                buffer.spawned.delete(entity);
                if (world.has(entity)) destroyEntity(world, entity);
                recountPending(world);
                return;
            }

            buffer.commands.push({ type: 'destroy', entity });
            recountPending(world);
        },

        add(entity: Entity, ...traits: ConfigurableTrait[]) {
            const buffer = topBuffer(world);
            for (const config of traits) {
                buffer.commands.push({ type: 'add', entity, config });
            }
            recountPending(world);
        },

        remove(entity: Entity, ...traits: (Trait | RelationPair)[]) {
            const buffer = topBuffer(world);
            for (const config of traits) {
                buffer.commands.push({ type: 'remove', entity, config });
            }
            recountPending(world);
        },

        addExclusive<T extends Trait>(
            entity: Entity,
            relation: Relation<T>,
            target: RelationTarget,
            params?: Record<string, unknown>
        ) {
            const buffer = topBuffer(world);
            buffer.commands.push({
                type: 'addExclusive',
                entity,
                relation: relation as unknown as Relation<Trait>,
                target,
                params,
            });
            recountPending(world);
        },

        flush() {
            flushBuffer(world, topBuffer(world));
        },
    };
