// --- Scope management (used by updateEach) ---------------------------------

export function beginDeferredScope(world: World): DeferredBuffer {
    const buffer = createDeferredBuffer();
    world[$internal].deferredStack.push(buffer);
    return buffer;
}

export function endDeferredScope(world: World, buffer: DeferredBuffer) {
    const stack = world[$internal].deferredStack;
    // Flush this scope's commands, then pop it so outer buffers remain.
    flushBuffer(world, buffer);
    const index = stack.lastIndexOf(buffer);
    if (index !== -1) stack.splice(index, 1);
    recountPending(world);
}

/**
 * Flush the buffers that hold pending commands for `entity`. Called before a
 * non-deferred mutation so the entity's observable state stays consistent.
 */
export function autoFlushForEntity(world: World, entity: Entity) {
    const ctx = world[$internal];
    if (ctx.deferredPending === 0 || ctx.deferredFlushing) return;
    // Copy the stack because flushing may not structurally change it, but be safe.
    const buffers = ctx.deferredStack.slice();
    for (const buffer of buffers) {
        if (buffer.commands.some((cmd) => cmd.entity === entity)) {
            flushBuffer(world, buffer);
        }
    }
}

